[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/argoRawProfiles> ;
            sh:resultMessage "A description of the resource is recommended for discovery" ;
            sh:resultPath schema1:description ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape cdifd:descriptionProperty ],
        [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/argoRawProfiles> ;
            sh:resultMessage "Date of most recent update to resource content is required, using ISO8601 format with at least a year and a month." ;
            sh:resultPath schema1:dateModified ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape cdifd:dateModifiedProperty ],
        [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/argoRawProfiles> ;
            sh:resultMessage "Keywords are recommended for discovery" ;
            sh:resultPath schema1:keywords ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape cdifd:keywordsProperty ],
        [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/argoRawProfiles> ;
            sh:resultMessage "To meet the requirements for FAIR data, information about licenses or other security, usage, or access limitations must be described" ;
            sh:resultPath [ sh:alternativePath ( schema1:license schema1:conditionsOfAccess ) ] ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape cdifd:rightsProperty ],
        [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/argoRawProfiles> ;
            sh:resultMessage "An identifier for the documented resource must be provided" ;
            sh:resultPath schema1:identifier ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape cdifd:resourceIdentifierProperty ],
        [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/argoRawProfiles> ;
            sh:resultMessage "At least one creator (author/originator) is recommended" ;
            sh:resultPath schema1:creator ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape cdifd:creatorProperty ] .

